#include<bits/stdc++.h>
using namespace std;

const int N = 1.1e7 + 5;

string s = "#";
int n, ans = 1, d[N];

void Manacher()
{
    int l = 0, r = -1;
    for(int i = 1; i < n; i++)
    {
        int k = 1;
        if(i <= r) k = min(d[l + r - i], r - i + 1);
        while(i - k >= 0 && i + k < n && s[i - k] == s[i + k]) 
            ++k;
        d[i] = k--;
        if(i + k > r)
        {
            r = i + k;
            l = i - k;
        }
        ans = max(ans, d[i]);
    }
}

int main()
{
    char c;
    while(c = getchar())
    {
        if(c < 'a' || c > 'z')
            break;
        s = s + c + "#";
    }
    n = s.size();
    Manacher();
    cout << ans - 1;
}
